import React, { useState, useCallback, useEffect } from 'react'
import { Trans, useTranslation } from 'react-i18next'
import PropTypes from 'prop-types'
import {
  Paragraph,
  Button,
  DialogOverlay,
  DialogOverlayActions,
  DialogOverlayFooter,
  Separator,
  useOverlay,
  useStatusOverlay,
} from '@fs/zion-ui'
import * as Yup from 'yup'
import { yupResolver } from '@hookform/resolvers/yup'
import ZionForm, { FormRadio, FormRadioGroup, FormTextArea, FormTextField, useZionForm } from '@fs/zion-form'
import { trackLink } from '@fs/zion-analytics'
import { Link } from '@fs/zion-router'
import { sendIssue, emailRegex, phoneRegex } from './lib/reportAbuseService'

export default function ReportAbuseOverlay({ overlay, subject, additionalInfo, onReportCreated }) {
  const [t] = useTranslation()
  const internalOverlay = useOverlay()
  const showStatusOverlay = useStatusOverlay()
  const [reportFeedback, setReportFeedback] = useState()
  const [inFlight, setInFlight] = useState(false)

  const methods = useZionForm({
    mode: 'all',
    defaultValues: {
      report: '',
      phoneNumber: '',
      email: '',
      typeOfAbuse: undefined,
    },
    resolver: yupResolver(
      Yup.object()
        .shape({
          report: Yup.string().required(
            t('report-abuse-overlay.description-required', 'Description of abuse required.')
          ),
          email: Yup.string().test(
            'email-format',
            t('report-abuse-overlay.email.required', 'Valid Email or Phone Number required.'),
            (value) => !value || value.match(emailRegex)
          ),
          phoneNumber: Yup.string().test(
            'phone-format',
            t('report-abuse-overlay.email.required', 'Valid Email or Phone Number required.'),
            (value) => !value || value.match(phoneRegex)
          ),
        })
        .test(
          'contact-required',
          t('report-abuse-overlay.email.required', 'Valid Email or Phone Number required.'),
          (values) => {
            const { email, phoneNumber } = values
            const hasValidEmail = email && email.match(emailRegex)
            const hasValidPhone = phoneNumber && phoneNumber.match(phoneRegex)
            return hasValidEmail || hasValidPhone
          }
        )
    ),
  })
  const { formState, getValues, reset } = methods
  const { isDirty, isValid } = formState

  useEffect(() => {
    if (!overlay.isOpen && overlay.transitioning) reset?.()
  }, [overlay, reset])

  const handleEmailBlur = useCallback(
    (event) => {
      if (event.target.value) delete formState.errors.phoneNumber
    },
    [formState.errors.phoneNumber]
  )

  const handlePhoneBlur = useCallback(
    (event) => {
      if (event.target.value) delete formState.errors.email
    },
    [formState.errors.email]
  )

  const onSubmit = useCallback(
    (values) => {
      setInFlight(true)
      sendIssue(values, subject, additionalInfo)
        .then((data) => {
          trackLink({ link_name: `report abuse overlay:send report:${getValues().typeOfAbuse}` })
          setReportFeedback(
            t(
              'report-abuse-overlay.creation.success',
              `Thank you for reporting this abuse. Incident number {caseNumber} was created and sent to FamilySearch Support for review. If needed, you will be contacted by email or phone.`,
              { caseNumber: data.issueId }
            )
          )
          overlay.close()
          internalOverlay.open()
          onReportCreated?.()
        })
        .catch(() => {
          showStatusOverlay({
            message: t(
              'report-abuse-overlay.creation.error',
              'Unable to create report of abuse, please try again later.'
            ),
          })
        })
        .finally(() => {
          setInFlight(false)
        })
    },
    [subject, additionalInfo, getValues, t, overlay, internalOverlay, onReportCreated, showStatusOverlay]
  )

  return (
    <>
      <DialogOverlay
        {...overlay}
        title={t('common-ui:report-abuse.action', 'Report Abuse')}
        as={ZionForm}
        methods={methods}
        onSubmit={onSubmit}
      >
        <Paragraph size="sm">
          <Trans i18nKey="report-abuse-overlay.dialog.body">
            <Link to="/legal/terms" target="_blank" external>
              Terms of Use
            </Link>
            <Link to="/legal/familysearch-upload-guidelines-and-policies" target="_blank" external>
              Memories Upload Guidelines and Policies
            </Link>
          </Trans>
        </Paragraph>
        <Separator size="sm" />
        <FormRadioGroup label={t('report-abuse-overlay.type-of-abuse.label', 'Type of Abuse')} disabled={inFlight}>
          <FormRadio
            label={t('report-abuse-overlay.offensive.option.label', 'Offensive')}
            name="typeOfAbuse"
            value="Offensive"
          />
          <FormRadio
            label={t('report-abuse-overlay.spam-advertising.option.label', 'Spam or Advertising')}
            name="typeOfAbuse"
            value="Spam"
          />
          <FormRadio
            label={t('report-abuse-overlay.political.option.label', 'Political Statement')}
            name="typeOfAbuse"
            value="Political"
          />
          <FormRadio
            label={t('report-abuse-overlay.harassment.option.label', 'Harassment')}
            name="typeOfAbuse"
            value="Harassment"
          />
          <FormRadio
            label={t('report-abuse-overlay.copyright.option.label', 'Copyright Infringement')}
            name="typeOfAbuse"
            value="Copyright"
          />
          <FormRadio label={t('report-abuse-overlay.other.option.label', 'Other')} name="typeOfAbuse" value="Other" />
        </FormRadioGroup>
        <FormTextArea
          label={t('report-abuse-overlay.report.label', 'Report')}
          placeholder={t('report-abuse-overlay.report.placeholder', 'Please explain your concern.')}
          name="report"
          disabled={inFlight}
        />
        <FormTextField
          label={t('report-abuse-overlay.email.label', 'Email')}
          placeholder={t('report-abuse-overlay.email.placeholder', 'Enter an email.')}
          helpMessage={t('report-abuse-overlay.email-phone-number.required', 'An email or a phone number is required.')}
          name="email"
          onBlur={handleEmailBlur}
          disabled={inFlight}
        />
        <FormTextField
          label={t('report-abuse-overlay.phone-number.label', 'Phone Number')}
          placeholder={t('report-abuse-overlay.phone-number.placeholder', 'Enter your phone number')}
          helpMessage={t('report-abuse-overlay.email-phone-number.required', 'An email or a phone number is required.')}
          name="phoneNumber"
          onBlur={handlePhoneBlur}
          disabled={inFlight}
        />

        <DialogOverlayFooter>
          <DialogOverlayActions>
            <Button data-testid="edit-overlay-reason.attached.cancel.button" onClick={overlay.close}>
              {t('common-ui:cancel.action', 'Cancel')}
            </Button>
            <Button
              aria-label={t('common-ui:submit.action', 'Submit')}
              type="submit"
              emphasis="high"
              disabled={!isValid || !isDirty || inFlight}
            >
              {t('common-ui:submit.action', 'Submit')}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </DialogOverlay>
      <DialogOverlay {...internalOverlay} title={t('common-ui:report-abuse.action', 'Report Abuse')}>
        {reportFeedback}
        <DialogOverlayFooter>
          <DialogOverlayActions>
            <Button aria-label={t('common-ui:close.action', 'Close')} onClick={internalOverlay.close}>
              {t('common-ui:close.action', 'Close')}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </DialogOverlay>
    </>
  )
}

ReportAbuseOverlay.propTypes = {
  /** The overlay returned from `useOverlay()`. */
  overlay: PropTypes.object.isRequired,
  /** String containing the summary of the issue.  This is mapped to the subject field in JIRA. */
  subject: PropTypes.string.isRequired,
  /** String containing any additional information to include in the 'Description' section of the Jira created by the Jira Support Issues system. */
  additionalInfo: PropTypes.string,
  /** Function called when the abuse report has been successfully created. */
  onReportCreated: PropTypes.func,
}
