import axios from '@fs/zion-axios'
import zionDebug from '@fs/zion-debug'
import { i18n } from '@fs/zion-locale'

const debug = zionDebug('messages:reportAbuse-client')

const URL_ISSUE_SERVICE = '/service/support/issues'
const PLATFORM_USERS_SERVICE = '/platform/users'
const IDENT_SESSION_SERVICE = '/service/ident/session'

export const emailRegex = /^\S+@\S+\.\S+$/
export const phoneRegex = /^[0-9() .,+/-]{8,20}$/

// TODO: [FRONTIER-366] Change to get the user from zion-user when it has been updated to return the givenName and familyName
async function getCurrentUser() {
  const url = `${PLATFORM_USERS_SERVICE}/current`
  try {
    const response = await axios.get(url, { headers: { 'Fs-User-Agent-Chain-Suffix': 'zion-report-abuse-overlay' } })
    return response?.data?.users?.[0] || null
  } catch (err) {
    debug(err)
    return null
  }
}

// TODO: [LYNX-4880] Get the `userName` field from `zion-session` when it is made available.
async function getUsernameFromSession() {
  const url = `${IDENT_SESSION_SERVICE}/sessions/CURRENT`
  try {
    const response = await axios.get(url, {
      headers: {
        accept: 'application/session-v1+json',
        'Fs-User-Agent-Chain-Suffix': 'zion-report-abuse-overlay',
      },
    })
    return response?.data?.userName
  } catch (err) {
    debug(err)
    return null
  }
}

export const sendIssue = async (form, subject, additionalInfo) => {
  try {
    const user = await getCurrentUser()
    let userName = await getUsernameFromSession()
    if (!userName)
      userName = `https://www.familysearch.org/en/dmconsole/user/${user.id.replace(
        'cis.user.',
        ''
      )}/summary?context=cisUserId`
    const body = {
      issueType: 'REPORT_ABUSE',
      cisid: user.id || 'unknown',
      givenName: user.givenName || 'unknown',
      familyName: user.familyName || 'unknown',
      phoneNumber: form.phoneNumber?.match(phoneRegex) ? form.phoneNumber : '',
      email: form.email?.match(emailRegex) ? form.email : '',
      subject: subject || `Report Abuse: ${form.typeOfAbuse}`,
      description:
        `Reason Reported: ${form.typeOfAbuse}\n` +
        `Contact Name: ${user.contactName}\n` +
        `Username: ${userName}\n` +
        `Helper Pin: ${user.helperAccessPin}\n` +
        `Birth Date: ${user.birthDate}\n` +
        `Description of Abuse: ${form.report}\n${additionalInfo ?? ''}`,
      helperInfo: `Username: ${userName}\nHelper Pin: ${user.helperAccessPin}`,
      lang: i18n.language,
      countryCode: user.country,
      autoApproved: false,
      checkExists: false,
    }

    const { data } = await axios.post(`${URL_ISSUE_SERVICE}/issues`, body)
    return data
  } catch (err) {
    debug(err)
    throw new Error(i18n.t('report-abuse-overlay.error-reportAbuse-send', 'Unable to send abuse report.'))
  }
}
export { sendIssue as default }
